package com.enterprise.app.repository;

import com.enterprise.app.entity.Transaction;
import com.enterprise.app.entity.TransactionStatus;
import com.enterprise.app.entity.TransactionType;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Modifying;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;
import org.springframework.stereotype.Repository;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;
import java.util.Optional;

@Repository
public interface TransactionRepository extends JpaRepository<Transaction, Long> {

    Optional<Transaction> findByReferenceNumber(String referenceNumber);

    List<Transaction> findByUserId(Long userId);

    Page<Transaction> findByUserId(Long userId, Pageable pageable);

    List<Transaction> findByStatus(TransactionStatus status);

    Page<Transaction> findByStatus(TransactionStatus status, Pageable pageable);

    List<Transaction> findByTransactionType(TransactionType transactionType);

    List<Transaction> findByUserIdAndStatus(Long userId, TransactionStatus status);

    List<Transaction> findByUserIdAndTransactionType(Long userId, TransactionType transactionType);

    @Query("SELECT t FROM Transaction t WHERE t.user.id = :userId " +
           "AND t.transactionDate BETWEEN :startDate AND :endDate")
    List<Transaction> findByUserIdAndDateRange(@Param("userId") Long userId,
                                                @Param("startDate") LocalDateTime startDate,
                                                @Param("endDate") LocalDateTime endDate);

    @Query("SELECT t FROM Transaction t WHERE t.transactionDate BETWEEN :startDate AND :endDate")
    Page<Transaction> findByDateRange(@Param("startDate") LocalDateTime startDate,
                                       @Param("endDate") LocalDateTime endDate,
                                       Pageable pageable);

    @Query("SELECT SUM(t.amount) FROM Transaction t WHERE t.user.id = :userId " +
           "AND t.transactionType = :type AND t.status = 'COMPLETED'")
    BigDecimal sumAmountByUserAndType(@Param("userId") Long userId,
                                       @Param("type") TransactionType type);

    @Query("SELECT SUM(t.amount) FROM Transaction t WHERE t.user.id = :userId " +
           "AND t.status = 'COMPLETED' AND t.transactionDate BETWEEN :startDate AND :endDate")
    BigDecimal sumCompletedAmountByUserAndDateRange(@Param("userId") Long userId,
                                                     @Param("startDate") LocalDateTime startDate,
                                                     @Param("endDate") LocalDateTime endDate);

    @Query("SELECT COUNT(t) FROM Transaction t WHERE t.user.id = :userId AND t.status = :status")
    long countByUserIdAndStatus(@Param("userId") Long userId, @Param("status") TransactionStatus status);

    @Modifying
    @Query("UPDATE Transaction t SET t.status = :status, t.processedAt = :processedAt WHERE t.id = :transactionId")
    int updateTransactionStatus(@Param("transactionId") Long transactionId,
                                 @Param("status") TransactionStatus status,
                                 @Param("processedAt") LocalDateTime processedAt);

    @Modifying
    @Query("UPDATE Transaction t SET t.status = 'FAILED', t.failureReason = :reason WHERE t.id = :transactionId")
    int markTransactionFailed(@Param("transactionId") Long transactionId, @Param("reason") String reason);

    @Query("SELECT t FROM Transaction t WHERE t.status = 'PENDING' AND t.createdAt < :cutoffTime")
    List<Transaction> findStalePendingTransactions(@Param("cutoffTime") LocalDateTime cutoffTime);

    @Query("SELECT t.transactionType, COUNT(t), SUM(t.amount) FROM Transaction t " +
           "WHERE t.user.id = :userId AND t.status = 'COMPLETED' GROUP BY t.transactionType")
    List<Object[]> getTransactionSummaryByUser(@Param("userId") Long userId);

    @Query(value = "SELECT DATE(t.transaction_date) as txn_date, COUNT(*) as txn_count, SUM(t.amount) as total_amount " +
           "FROM transactions t WHERE t.user_id = :userId AND t.status = 'COMPLETED' " +
           "GROUP BY DATE(t.transaction_date) ORDER BY txn_date DESC", nativeQuery = true)
    List<Object[]> getDailyTransactionSummary(@Param("userId") Long userId);

    boolean existsByReferenceNumber(String referenceNumber);
}


