package com.enterprise.app.mapper;

import com.enterprise.app.dto.CreateTransactionRequest;
import com.enterprise.app.dto.TransactionDTO;
import com.enterprise.app.entity.Transaction;
import com.enterprise.app.entity.User;
import org.springframework.stereotype.Component;

@Component
public class TransactionMapper {

    public TransactionDTO toDTO(Transaction transaction) {
        if (transaction == null) return null;
        TransactionDTO dto = new TransactionDTO();
        dto.setId(transaction.getId());
        dto.setReferenceNumber(transaction.getReferenceNumber());
        dto.setUserId(transaction.getUser().getId());
        dto.setUsername(transaction.getUser().getUsername());
        dto.setAmount(transaction.getAmount());
        dto.setCurrency(transaction.getCurrency());
        dto.setTransactionType(transaction.getTransactionType());
        dto.setStatus(transaction.getStatus());
        dto.setDescription(transaction.getDescription());
        dto.setSourceAccount(transaction.getSourceAccount());
        dto.setDestinationAccount(transaction.getDestinationAccount());
        dto.setTransactionDate(transaction.getTransactionDate());
        dto.setProcessedAt(transaction.getProcessedAt());
        dto.setCreatedAt(transaction.getCreatedAt());
        return dto;
    }

    public Transaction toEntity(CreateTransactionRequest request, User user) {
        if (request == null) return null;
        Transaction transaction = new Transaction();
        transaction.setUser(user);
        transaction.setAmount(request.getAmount());
        transaction.setCurrency(request.getCurrency() != null ? request.getCurrency() : "USD");
        transaction.setTransactionType(request.getTransactionType());
        transaction.setDescription(request.getDescription());
        transaction.setSourceAccount(request.getSourceAccount());
        transaction.setDestinationAccount(request.getDestinationAccount());
        return transaction;
    }
}


