    @Override
    @Transactional(readOnly = true)
    public BigDecimal getUserTotalByType(Long userId, TransactionType type) {
        if (!userRepository.existsById(userId)) {
            throw new ResourceNotFoundException("User", "id", userId);
        }
        BigDecimal total = transactionRepository.sumAmountByUserAndType(userId, type);
        return total != null ? total : BigDecimal.ZERO;
    }

    @Override
    @Transactional(readOnly = true)
    public List<TransactionSummaryDTO> getUserTransactionSummary(Long userId) {
        if (!userRepository.existsById(userId)) {
            throw new ResourceNotFoundException("User", "id", userId);
        }
        List<Object[]> results = transactionRepository.getTransactionSummaryByUser(userId);
        return results.stream()
                .map(row -> new TransactionSummaryDTO(
                        row[0].toString(),
                        ((Number) row[1]).longValue(),
                        (BigDecimal) row[2]
                ))
                .collect(Collectors.toList());
    }

    @Override
    @Transactional(readOnly = true)
    public long countUserTransactionsByStatus(Long userId, TransactionStatus status) {
        return transactionRepository.countByUserIdAndStatus(userId, status);
    }

    private String generateReferenceNumber() {
        String reference;
        do {
            reference = "TXN-" + UUID.randomUUID().toString().substring(0, 12).toUpperCase();
        } while (transactionRepository.existsByReferenceNumber(reference));
        return reference;
    }

